from __future__ import annotations

import argparse
import shutil
import subprocess
import sys
from pathlib import Path


DOC = """
Dependency Management Best Practices
====================================

Goal
----
Keep dependency versions consistent across local development, CI, and production by committing lock files to version control and updating them in a controlled, reviewable way.

Recommended Approaches
----------------------
1. pip workflow:
   - Maintain a small direct dependency file such as requirements.in
   - Generate a fully pinned requirements.txt with hashes
   - Commit both files
   - Install using:
       pip install --require-hashes -r requirements.txt

2. Poetry workflow:
   - Maintain dependencies in pyproject.toml
   - Generate/update poetry.lock
   - Commit both files
   - Install using:
       poetry install --sync

Why lock files matter
---------------------
- Reproducible builds across environments
- Prevents unexpected upgrades from indirect dependencies
- Improves security review and dependency auditing
- Makes deployments deterministic

Repository Conventions
----------------------
If using pip-tools:
- requirements.in: direct dependencies only
- requirements.txt: generated, fully pinned, includes hashes
- dev-requirements.in or requirements-dev.in: optional dev-only direct dependencies
- dev-requirements.txt or requirements-dev.txt: generated dev lock file

If using Poetry:
- pyproject.toml: dependency declarations and project metadata
- poetry.lock: exact resolved dependency versions

Standard pip-tools Workflow
---------------------------
Initial setup:
1. Add direct runtime dependencies to requirements.in
2. Generate a locked file:
     pip-compile --generate-hashes --output-file=requirements.txt requirements.in
3. Install exactly:
     pip install --require-hashes -r requirements.txt

For development dependencies:
1. Add direct dev dependencies to requirements-dev.in
2. Reference runtime file if desired:
     -r requirements.txt
     pytest
     black
3. Generate:
     pip-compile --generate-hashes --output-file=requirements-dev.txt requirements-dev.in
4. Install:
     pip install --require-hashes -r requirements-dev.txt

Updating dependencies with pip-tools
------------------------------------
Controlled update of all dependencies:
    pip-compile --generate-hashes --upgrade --output-file=requirements.txt requirements.in

Update a specific package only:
    pip-compile --generate-hashes --upgrade-package PACKAGE --output-file=requirements.txt requirements.in

After updating:
- Run tests
- Review version changes in the diff
- Merge only after CI passes

Standard Poetry Workflow
------------------------
Initial setup:
1. Add dependencies:
     poetry add requests
     poetry add --group dev pytest black
2. Generate or refresh lock file:
     poetry lock
3. Install exactly:
     poetry install --sync

Updating dependencies with Poetry
---------------------------------
Update according to version constraints:
    poetry update

Update a single package:
    poetry update requests

If dependency constraints need to change:
- Edit pyproject.toml or use poetry add with a new constraint
- Re-lock dependencies
- Run tests
- Commit both pyproject.toml and poetry.lock

Team Policy Recommendations
---------------------------
- Always commit lock files
- Never hand-edit generated lock files
- Review dependency diffs in pull requests
- Prefer scheduled dependency update PRs
- Keep direct dependency files small and intentional
- Separate runtime and development dependencies
- Validate lock files in CI
- Use exact installs in deployment, never floating installs

CI/CD Recommendations
---------------------
For pip:
- Verify lock file generation is up to date:
    pip-compile --generate-hashes --quiet --output-file=requirements.txt requirements.in
    git diff --exit-code requirements.txt
- Install with:
    pip install --require-hashes -r requirements.txt

For Poetry:
- Verify lock consistency:
    poetry lock --no-update
    git diff --exit-code poetry.lock
- Install with:
    poetry install --sync

Production Deployment Guidance
------------------------------
- Deploy from committed lock files only
- Do not resolve dependencies dynamically during deployment if avoidable
- Use the same Python version family in dev, CI, and prod
- Rebuild lock files when changing Python minor versions if necessary

Suggested Team Process
----------------------
1. Developer changes requirements.in or pyproject.toml
2. Developer regenerates requirements.txt or poetry.lock
3. Developer runs tests locally
4. Pull request includes both source dependency spec and lock file changes
5. CI validates lock files and test suite
6. Production installs from the committed lock file only

Example Files
-------------
requirements.in:
    flask
    requests>=2.31,<3

requirements-dev.in:
    -r requirements.txt
    pytest
    ruff

Commands:
    pip-compile --generate-hashes --output-file=requirements.txt requirements.in
    pip-compile --generate-hashes --output-file=requirements-dev.txt requirements-dev.in

Example Poetry Commands
-----------------------
    poetry add flask requests@^2.31
    poetry add --group dev pytest ruff
    poetry lock
    poetry install --sync
"""


def run(cmd: list[str]) -> int:
    print("+", " ".join(cmd))
    result = subprocess.run(cmd)
    return result.returncode


def require_tool(name: str, install_hint: str) -> None:
    if shutil.which(name) is None:
        print(f"Required tool not found: {name}", file=sys.stderr)
        print(install_hint, file=sys.stderr)
        sys.exit(1)


def pip_compile(
    input_file: str = "requirements.in",
    output_file: str = "requirements.txt",
    upgrade: bool = False,
    package: str | None = None,
) -> int:
    require_tool("pip-compile", "Install pip-tools: python -m pip install pip-tools")
    cmd = ["pip-compile", "--generate-hashes", "--output-file", output_file]
    if upgrade:
        cmd.append("--upgrade")
    if package:
        cmd.extend(["--upgrade-package", package])
    cmd.append(input_file)
    return run(cmd)


def poetry_lock(no_update: bool = False) -> int:
    require_tool("poetry", "Install Poetry: https://python-poetry.org/docs/")
    cmd = ["poetry", "lock"]
    if no_update:
        cmd.append("--no-update")
    return run(cmd)


def poetry_update(package: str | None = None) -> int:
    require_tool("poetry", "Install Poetry: https://python-poetry.org/docs/")
    cmd = ["poetry", "update"]
    if package:
        cmd.append(package)
    return run(cmd)


def check_pip_files() -> int:
    input_path = Path("requirements.in")
    output_path = Path("requirements.txt")
    if not input_path.exists():
        print("requirements.in not found")
        return 1
    if not output_path.exists():
        print("requirements.txt not found")
        return 1
    print("Found pip dependency files:")
    print(f"  - {input_path}")
    print(f"  - {output_path}")
    print("To validate sync in CI:")
    print("  pip-compile --generate-hashes --quiet --output-file=requirements.txt requirements.in")
    print("  git diff --exit-code requirements.txt")
    return 0


def check_poetry_files() -> int:
    pyproject = Path("pyproject.toml")
    lock = Path("poetry.lock")
    if not pyproject.exists():
        print("pyproject.toml not found")
        return 1
    if not lock.exists():
        print("poetry.lock not found")
        return 1
    print("Found Poetry dependency files:")
    print(f"  - {pyproject}")
    print(f"  - {lock}")
    print("To validate sync in CI:")
    print("  poetry lock --no-update")
    print("  git diff --exit-code poetry.lock")
    return 0


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(description="Dependency lock file management helper")
    sub = parser.add_subparsers(dest="command", required=True)

    sub.add_parser("docs", help="Print dependency management documentation")
    sub.add_parser("check", help="Check which lock-file workflow files exist")

    p1 = sub.add_parser("pip-compile", help="Generate requirements.txt from requirements.in")
    p1.add_argument("--input", default="requirements.in")
    p1.add_argument("--output", default="requirements.txt")

    p2 = sub.add_parser("pip-update", help="Update pip lock file")
    p2.add_argument("--input", default="requirements.in")
    p2.add_argument("--output", default="requirements.txt")
    p2.add_argument("--package", default=None)

    p3 = sub.add_parser("poetry-lock", help="Generate or refresh poetry.lock")
    p3.add_argument("--no-update", action="store_true")

    p4 = sub.add_parser("poetry-update", help="Update Poetry dependencies")
    p4.add_argument("--package", default=None)

    return parser


def main() -> int:
    parser = build_parser()
    args = parser.parse_args()

    if args.command == "docs":
        print(DOC.strip())
        return 0

    if args.command == "check":
        pip_ok = check_pip_files() == 0
        poetry_ok = check_poetry_files() == 0
        if not pip_ok and not poetry_ok:
            print("No recognized dependency workflow files found.")
            return 1
        return 0

    if args.command == "pip-compile":
        return pip_compile(input_file=args.input, output_file=args.output)

    if args.command == "pip-update":
        return pip_compile(
            input_file=args.input,
            output_file=args.output,
            upgrade=True,
            package=args.package,
        )

    if args.command == "poetry-lock":
        return poetry_lock(no_update=args.no_update)

    if args.command == "poetry-update":
        return poetry_update(package=args.package)

    parser.print_help()
    return 1


if __name__ == "__main__":
    raise SystemExit(main())